When using a Relationship to serialize a compound document, if the related Schema specifies an attribute name for the id field, the related data object is wrong (it serializes the whole object as a string).

Here's an example of the happy case, which works perfectly well:

```
from pprint import pprint
from marshmallow_jsonapi import fields, Schema

class BookSchema(Schema):
    id = fields.Str()
    title = fields.Str()
    author = fields.Relationship(
        include_resource_linkage=True,
        type_='authors',
        schema='AuthorSchema',
    )

    class Meta:
        type_ = 'books'
        strict = True

class AuthorSchema(Schema):
    id = fields.Str()

    class Meta:
        type_ = 'authors'
        strict = True

book_data = {
    'id': '978-1451673319',
    'title': 'Fahrenheit 451',
    'author': {'id': 'Ray Bradbury'},
}

book_schema = BookSchema(include_data=['author'])
pprint(book_schema.dump(book_data).data)

# {'data': {'attributes': {u'title': u'Fahrenheit 451'},
#           'id': u'978-1451673319',
#           'relationships': {
#               u'author': {'data': {
#                   'id': 'Ray Bradbury',
#                   'type': 'authors'}}
#           },
#           'type': 'books'},
#  'included': [{'id': u'Ray Bradbury', 'type': 'authors'}]}
```

Now if you only change the `AuthorSchema` and the input data, as follows, then the relationship data object is toast:

```
class AuthorSchema(Schema):
    id = fields.Str(attribute='name')  # <---- changed this

    class Meta:
        type_ = 'authors'
        strict = True

book_data = {
    'id': '978-1451673319',
    'title': 'Fahrenheit 451',
    'author': {'name': 'Ray Bradbury'},  # <---- and changed this
}

book_schema = BookSchema(include_data=['author'])
pprint(book_schema.dump(book_data).data)

# {'data': {'attributes': {u'title': u'Fahrenheit 451'},
#           'id': u'978-1451673319',
#           'relationships': {
#               u'author': {'data': {
#                   'id': "{'name': 'Ray Bradbury'}",  <--- what happened here??
#                   'type': 'authors'}}
#           },
#           'type': 'books'},
#  'included': [{'id': u'Ray Bradbury', 'type': 'authors'}]}
```

