#include <pybind11/pybind11.h>
#include <pybind11/stl.h>

#include <iostream>

struct Struct {
    Struct() : str("Hello") {}
    std::string str;
};

void print_it(Struct number)
{
    std::cout << number.str << std::endl;
}

namespace py = pybind11;

PYBIND11_PLUGIN(example) {
    py::module m("example", "pybind11 example plugin");

    py::class_<Struct>(m, "Struct")
    .def(py::init<>())
    .def("__getstate__", [](const Struct& num) {
        return py::make_tuple(num.str);
    })
    .def("__setstate__", [](Struct& num, py::tuple t) {
        if (t.size() != 1) {
            throw std::runtime_error("Invalid state!");
        }
        num.str = t[0].cast<std::string>();
    });

    m.def("print_it", &print_it, "Function loading data from file");

    return m.ptr();
}

```

